#include<bits/stdc++.h>
using namespace std;
long long n;
struct edge
{
    long long u,v,w;
    bool operator<(const edge&b)const
    {
        return w>b.w;
    }
}e[400010],e1[400010];
long long s[400010],sum,id[400010];
long long lowbit(long long x)
{
    return x&-x;
}
void update(long long x,long long v)
{
    for(long long i=x;i<=n+5;i+=lowbit(i))
    {
        s[i]+=v;
    }
}
void add(long long l,long long r,long long v)
{
    sum+=(r-l+1)*v;
    for(l--;r>l;r&=r-1)
    {
        s[r]+=v;
    }
    for(;l>r;l&=l-1)
    {
        s[l]-=v;
    }
}
long long query(long long x)
{
    long long ans=0;
    for(long long i=x;i<=n;i+=lowbit(i))
    {
        ans+=s[i];
    }
    return ans;
}
long long fa[400010],ls[400010],rs[400010];
long long find(long long x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
long long dfncnt,dfnl[400010],dfnr[400010];
void dfs(long long x)
{
    dfnl[x]=dfncnt+1;
    if(x<=n)
    {
        dfncnt++;
    }
    else
    {
        dfs(ls[x]);
        dfs(rs[x]);
    }
    dfnr[x]=dfncnt;
}
bool cmp(int x,int y)
{
    return e[x].w>e[y].w;
}
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<n;i++)
    {
        scanf("%lld%lld%lld",&e[i].u,&e[i].v,&e[i].w);
    }
    for(long long i=1;i<n*2;i++)
    {
        id[i]=i;
        fa[i]=i;
    }
    stable_sort(id+1,id+n,cmp);
    for(long long i=n-1;i>=1;i--)
    {
        ls[n+i]=find(e[id[i]].u);
        rs[n+i]=find(e[id[i]].v);
        fa[ls[n+i]]=fa[rs[n+i]]=n+i;
    }
    dfs(n+1);
    long long x=0,y=0;
    for(long long i=1;i<n;i++)
    {
        add(dfnl[ls[n+i]],dfnr[ls[n+i]],e[id[i]].w*(dfnr[rs[n+i]]-dfnr[ls[n+i]]));
        add(dfnl[rs[n+i]],dfnr[rs[n+i]],e[id[i]].w*(dfnl[rs[n+i]]-dfnl[ls[n+i]]));
        long long u,k;
        scanf("%lld%lld",&u,&k);
        u^=x;
        k^=x;
        add(dfnl[u],dfnl[u],k-query(dfnl[u]));
        x=sum;
        y^=x;
    }
    printf("%lld",y);
    return 0;
}
